{'Fn::Sub': '{
  "Comment": "Image recognition workflow",
  "StartAt": "ValidateFileExtension",
  "States": {
    "ValidateFileExtension": {
      "Type": "Choice",
      "Choices": [
        {
          "Variable": "$.objectKey",
          "StringMatches": "*.jpg",
          "Next": "DetectLabels"
        },
        {
          "Variable": "$.objectKey",
          "StringMatches": "*.jpeg",
          "Next": "DetectLabels"
        },
        {
          "Variable": "$.objectKey",
          "StringMatches": "*.png",
          "Next": "DetectLabels"
        }
      ],
      "Default": "InvalidFileExtension"
    },
    "InvalidFileExtension": {
      "Type": "Fail",
      "Error": "InvalidFileExtension",
      "Cause": "The uploaded file extension is not supported."
    },
    "DetectLabels": {
      "Type": "Task",
      "Resource": "arn:aws:states:::aws-sdk:rekognition:detectLabels",
      "Parameters": {
        "Image": {
          "S3Object": {
            "Bucket": "$.bucket",
            "Name": "$.objectKey"
          }
        },
        "MaxLabels": 10,
        "MinConfidence": 70
      },
      "Next": "ProcessResults"
    },
    "ProcessResults": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${ProcessLabelsFunctionArn}",
        "Payload": {
          "bucket.$": "$.bucket",
          "objectKey.$": "$.objectKey",
          "Labels.$": "$.Labels"
        }
      },
      "End": true
    }
  }
}
', 'Variables': {'ProcessLabelsFunctionArn': {'Fn::GetAtt': ['ProcessLabelsFunction', 'Arn']}}} is not of type 'string'
